INSERT INTO `items` VALUES (1,'master-ball','Master Ball','standard-balls',0,NULL,'Catches a wild Pokémon every time.','Used in battle : Catches a wild Pokémon without fail. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(2,'ultra-ball','Ultra Ball','standard-balls',800,NULL,'Tries to catch a wild Pokémon. Success rate is 2×.','Used in battle : Attempts to catch a wild Pokémon, using a catch rate of 2×. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(3,'great-ball','Great Ball','standard-balls',600,NULL,'Tries to catch a wild Pokémon. Success rate is 1.5×.','Used in battle : Attempts to catch a wild Pokémon, using a catch rate of 1.5×. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(4,'poke-ball','Poké Ball','standard-balls',200,NULL,'Tries to catch a wild Pokémon.','Used in battle : Attempts to catch a wild Pokémon, using a catch rate of 1×. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(5,'safari-ball','Safari Ball','standard-balls',0,NULL,'Tries to catch a wild Pokémon in the Great Marsh or Safari Zone. Success rate is 1.5×.','Used in battle : Attempts to catch a wild Pokémon, using a catch rate of 1.5×. This item can only be used in the Great Marsh or Safari Zone.',0,1,NULL),(6,'net-ball','Net Ball','special-balls',1000,NULL,'Tries to catch a wild Pokémon. Success rate is 3× for water and bug Pokémon.','Used in battle : Attempts to catch a wild Pokémon. If the wild Pokémon is Water- or Bug-type, this ball has a catch rate of 3×. Otherwise, it has a catch rate of 1×. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(7,'dive-ball','Dive Ball','special-balls',1000,NULL,'Tries to catch a wild Pokémon. Success rate is 3.5× when underwater, fishing, or surfing.','Used in battle : Attempts to catch a wild Pokémon. If the wild Pokémon was encountered by surfing or fishing, this ball has a catch rate of 3.5×. Otherwise, it has a catch rate of 1×. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(8,'nest-ball','Nest Ball','special-balls',1000,NULL,'Tries to catch a wild Pokémon. Success rate is 3.9× for level 1 Pokémon, and drops steadily to 1× at level 30.','Used in battle : Attempts to catch a wild Pokémon. Has a catch rate of given by `(40 - level) / 10`, where `level` is the wild Pokémon’s level, to a maximum of 3.9× for level 1 Pokémon. If the wild Pokémon’s level is higher than 30, this ball has a catch rate of 1×. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(9,'repeat-ball','Repeat Ball','special-balls',1000,NULL,'Tries to catch a wild Pokémon. Success rate is 3× for previously-caught Pokémon.','Used in battle : Attempts to catch a wild Pokémon. If the wild Pokémon’s species is marked as caught in the trainer’s Pokédex, this ball has a catch rate of 3×. Otherwise, it has a catch rate of 1×. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(10,'timer-ball','Timer Ball','special-balls',1000,NULL,'Tries to catch a wild Pokémon. Success rate increases by 0.1× (Gen V: 0.3×) every turn, to a max of 4×.','Used in battle : Attempts to catch a wild Pokémon. Has a catch rate of 1.1× on the first turn of the battle and increases by 0.1× every turn, to a maximum of 4× on turn 30. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(11,'luxury-ball','Luxury Ball','special-balls',3000,NULL,'Tries to catch a wild Pokémon. Caught Pokémon start with 200 happiness.','Used in battle : Attempts to catch a wild Pokémon, using a catch rate of 1×. Whenever the caught Pokémon’s happiness increases, it increases by one extra point. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(12,'premier-ball','Premier Ball','special-balls',20,NULL,'Tries to catch a wild Pokémon.','Used in battle : Attempts to catch a wild Pokémon, using a catch rate of 1×. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(13,'dusk-ball','Dusk Ball','special-balls',1000,NULL,'Tries to catch a wild Pokémon. Success rate is 3.5× at night and in caves.','Used in battle : Attempts to catch a wild Pokémon. If it’s currently nighttime or the wild Pokémon was encountered while walking in a cave, this ball has a catch rate of 3.5×. Otherwise, it has a catch rate of 1×. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(14,'heal-ball','Heal Ball','special-balls',300,NULL,'Tries to catch a wild Pokémon. Caught Pokémon are immediately healed.','Used in battle : Attempts to catch a wild Pokémon, using a catch rate of 1×. The caught Pokémon’s HP is immediately restored, PP for all its moves is restored, and any status ailment is cured. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(15,'quick-ball','Quick Ball','special-balls',1000,NULL,'Tries to catch a wild Pokémon. Success rate is 4× (Gen V: 5×), but only on the first turn.','Used in battle : Attempts to catch a wild Pokémon, using a catch rate of 4× on the first turn of a battle, but 1× any other time. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(16,'cherish-ball','Cherish Ball','special-balls',0,NULL,'Tries to catch a wild Pokémon.','Used in battle : Attempts to catch a wild Pokémon, using a catch rate of 1×. If used in a trainer battle, nothing happens and the ball is lost.',0,1,NULL),(17,'potion','Potion','healing',200,30,'Restores 20 HP.','Used on a friendly Pokémon : Restores 20 HP.',0,1,NULL),(18,'antidote','Antidote','status-cures',200,30,'Cures poison.','Used on a party Pokémon : Cures poison.',0,1,NULL),(19,'burn-heal','Burn Heal','status-cures',200,30,'Cures a burn.','Used on a party Pokémon : Cures a burn.',0,1,NULL),(20,'ice-heal','Ice Heal','status-cures',200,30,'Cures freezing.','Used on a party Pokémon : Cures freezing.',0,1,NULL),(21,'awakening','Awakening','status-cu