INSERT INTO `moves` VALUES (1,'pound','Pound','normal','physical',40,100,35,35,0,'selected-pokemon',NULL,'Inflicts regular damage with no additional effect.','Inflicts regular damage.',1,0,0,NULL),(2,'karate-chop','Karate Chop','fighting','physical',50,100,25,25,0,'selected-pokemon',NULL,'Has an increased chance for a critical hit.','Inflicts regular damage. User’s critical hit rate is one level higher when using this move.',1,0,0,NULL),(3,'double-slap','Double Slap','normal','physical',15,85,10,10,0,'selected-pokemon',NULL,'Hits 2-5 times in one turn.','Inflicts regular damage. Hits 2–5 times in one turn. Has a 3/8 chance each to hit 2 or 3 times, and a 1/8 chance each to hit 4 or 5 times. Averages to 3 hits per use.',1,0,0,NULL),(4,'comet-punch','Comet Punch','normal','physical',18,85,15,15,0,'selected-pokemon',NULL,'Hits 2-5 times in one turn.','Inflicts regular damage. Hits 2–5 times in one turn. Has a 3/8 chance each to hit 2 or 3 times, and a 1/8 chance each to hit 4 or 5 times. Averages to 3 hits per use.',1,0,0,NULL),(5,'mega-punch','Mega Punch','normal','physical',80,85,20,20,0,'selected-pokemon',NULL,'Inflicts regular damage with no additional effect.','Inflicts regular damage.',1,0,0,NULL),(6,'pay-day','Pay Day','normal','physical',40,100,20,20,0,'selected-pokemon',NULL,'Scatters money on the ground worth five times the user’s level.','Inflicts regular damage. After the battle ends, the winner receives five times the user’s level in extra money for each time this move was used.',1,0,0,NULL),(7,'fire-punch','Fire Punch','fire','physical',75,100,15,15,0,'selected-pokemon',10,'Has a chance to burn the target.','Inflicts regular damage. Has a chance to burn the target.',1,0,0,NULL),(8,'ice-punch','Ice Punch','ice','physical',75,100,15,15,0,'selected-pokemon',10,'Has a chance to freeze the target.','Inflicts regular damage. Has a chance to freeze the target.',1,0,0,NULL),(9,'thunder-punch','Thunder Punch','electric','physical',75,100,15,15,0,'selected-pokemon',10,'Has a chance to paralyze the target.','Inflicts regular damage. Has a chance to paralyze the target.',1,0,0,NULL),(10,'scratch','Scratch','normal','physical',40,100,35,35,0,'selected-pokemon',NULL,'Inflicts regular damage with no additional effect.','Inflicts regular damage.',1,0,0,NULL),(11,'vice-grip','Vise Grip','normal','physical',55,100,30,30,0,'selected-pokemon',NULL,'Inflicts regular damage with no additional effect.','Inflicts regular damage.',1,0,0,NULL),(12,'guillotine','Guillotine','normal','physical',NULL,30,5,5,0,'selected-pokemon',NULL,'Causes a one-hit KO.','Inflicts damage equal to the target’s max HP. Ignores accuracy and evasion modifiers. This move’s accuracy is 30% plus 1% for each level the user is higher than the target. If the user is a lower level than the target, this move will fail. Because this move inflicts a specific and finite amount of damage, Endure still prevents the target from fainting. The effects of Lock-On, Mind Reader, and No Guard still apply, as long as the user is equal or higher level than the target. However, they will not give this move a chance to break through Detect or Protect.',1,0,0,NULL),(13,'razor-wind','Razor Wind','normal','special',80,100,10,10,0,'all-opponents',NULL,'Requires a turn to charge before attacking.','Inflicts regular damage. User’s critical hit rate is one level higher when using this move. User charges for one turn before attacking. This move cannot be selected by Sleep Talk.',1,0,0,NULL),(14,'swords-dance','Swords Dance','normal','status',NULL,NULL,20,20,0,'user',NULL,'Raises the user’s Attack by two stages.','Raises the user’s Attack by two stages.',1,0,0,NULL),(15,'cut','Cut','normal','physical',50,95,30,30,0,'selected-pokemon',NULL,'Inflicts regular damage with no additional effect.','Inflicts regular damage.',1,1,0,NULL),(16,'gust','Gust','flying','special',40,100,35,35,0,'selected-pokemon',NULL,'Inflicts regular damage and can hit Pokémon in the air.','Inflicts regular damage. If the target is under the effect of Bounce, Fly, or Sky Drop, this move will hit with double power.',1,0,0,NULL),(17,'wing-attack','Wing Attack','flying','physical',60,100,35,35,0,'selected-pokemon',NULL,'Inflicts regular damage with no additional effect.','Inflicts regular damage.',1,0,0,NULL),(18,'whirlwind','Whirlwind','normal','status',NULL,NULL,20,20,-6,'selected-pokemon',NULL,'Immediately ends wild battles. Forces trainers to switch Pokémon.','Switches the target out for another of its trainer’s Pokémon selected at random. Wild battles end immediately. Doesn’t affect Pokémon with Suction Cups or under the effect of Ingrain.',1,0,0,NULL),(19,'fly','Fly','flying','physical',90,95,15,15,0,'selected-pokemon',NULL,'User flies high into the air, dodging all attacks, and hits next turn.','Inflicts regular damage. User flies high into the air for one turn, becoming immune to attack, and hits on the second turn. During the immune turn, Gust, Hurricane, Sky Uppercut, Smack Down, Thunder, Twister, and Whirlwind still hit the user normally. Gust and Twister also have double power against the user. The damage from Hail and Sandstorm still applies during the immune turn. The user may be hit during its immune turn if under the effect of Lock-On, Mind Reader, or No Guard. This move cannot be used while Gravity is in effect. This move cannot be selected by Sleep Talk.',1,0,0,NULL),(20,'bind','Bind','normal','physical',15,85,20,20,0,'selected-pokemon',100,'Prevents the target from fleeing and inflicts damage for 2-5 turns.','Inflicts regular damage. For the next 2–5 turns, the target cannot leave the field and is damaged for 1/16 its max HP at the end of each turn. The user continues to use other moves during this time. If the user leaves the field, this effect ends. Has a 3/8 chance each to hit 2 or 3 times, and a 1/8 chance each to hit 4 or 5 times. Averages to 3 hits per use. Rapid Spin cancels this effect.',1,0,0,NULL),(21,'slam','Slam','normal','physical',80,75,20,20,0,'selected-pokemon',NULL,'Inflicts regular damage with no additional effect.','Inflicts regular damage.',1,0,0,NULL),(22,'vine-whip','Vine Whip','grass','physical',45,100,25,25,0,'selected-pokemon',NULL,'Inflicts regular damage with no additional effect.','Inflicts regular damage.',1,0,0,NULL),(23,'stomp','Stomp','normal','physical',65,100,20,20,0,'selected-pokemon',30,'Has a chance to make the target flinch.','Inflicts regular damage. Has a chance to make the target flinch. Power is doubled against Pokémon that have used Minimize since entering the field.',1,0,0,NULL),(24,'double-kick','Double Kick','fighting','physical',30,100,30,30,0,'selected-pokemon',NULL,'Hits twice in one turn.','Inflicts regular damage. Hits twice in one turn.',1,0,0,NULL),(25,'mega-kick','Mega Kick','normal','physical',120,75,5,5,0,'selected-pokemon',NULL,'Inflicts regular damage with no additional effect.','Inflicts regular damage.',1,0,0,NULL),(26,'jump-kick','Jump Kick','fighting','physical',100,95,10,10,0,'selected-pokemon',NULL,'If the user misses, it takes half the damage it would have inflicted in recoil.','Inflicts regular damage. If this move misses, is blocked by Protect or Detect, or has no effect, the user takes damage equal to half of its max HP rounded down. This move cannot be used while Gravity is in effect.',1,0,0,NULL),(27,'rolling-kick','Rolling Kick','fighting','physical',60,85,15,15,0,'selected-pokemon',30,'Has a chance to make the target flinch.','Inflicts regular damage. Has a chance to make the target flinch.',1,0,0,NULL),(28,'sand-attack','Sand Attack','ground','status',NULL,100,15,15,0,'selected-pokemon',NULL,'Lowers the target’s accuracy by one stage.','Lowers the target’s accuracy by one stage.',1,0,0,NULL),(29,'headbutt','Headbutt','normal','physical',70,100,15,15,0,'selected-pokemon',30,'Has a chance to make the target flinch.','Inflicts regular damage. Has a chance to make the target flinch.',1,0,0,NULL),(30,'horn-attack','Horn Attack','normal','physical',65,100,25,25,0,'s